(1, 1, 1, 1, 1, NULL, 1, '2024-07-28 14:22:25', '2024-07-28 14:22:25');
INSERT INTO `activerecall_questions` (`id`, `created_by`, `quiz_id`, `question_name`, `question_type`, `section`, `type`, `chapter`, `option1`, `option2`, `option3`, `option4`, `answer`, `answer_explanation`, `status`, `created_at`, `updated_at`) VALUES
(1, 1, 1, 'What is the APF for a positive pressure demand SCBA?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Positive pressure demand SCBAs with full facepiece typically have an APF (assigned protection factor) of 10,000. This means that if properly fitted, the wearer can be exposed to 10,000 times the PEL.', NULL, 1, '2024-07-28 14:23:02', '2024-07-28 14:23:02'),
(3, 1, 1, '<p>Classes of Flammable Liquids</p>', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, '<p>Class &nbsp;&nbsp;&nbsp;&nbsp; Characteristics</p><p>IA &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Flash point below 73°F; boiling point below 100°F&nbsp;</p><p>IB &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Flash point below 73°F; boiling point at or above 100°F&nbsp;</p><p>IC&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Flash point at or above 73°F, but below 100°F</p>', NULL, 1, '2024-08-13 08:44:31', '2024-08-25 18:58:19'),
(4, 1, 1, 'What colors are used for\r\na. First-aid and safety equipment\r\nb. Maintenance equipment\r\nc. Fire protection equipment\r\nd. Hazardous parts on machinery', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'a. First-aid and safety equipment uses the color green.\r\nb. Maintenance equipment has no standardized color.\r\nc. Fire protection equipment uses the color red.\r\nd. Hazardous parts on machinery are often colored yellow, orange or red', NULL, 1, '2024-08-18 15:42:13', '2024-08-18 15:42:13'),
(5, 1, 1, 'Classes of Combustible Liquids', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Class          Characteristics\r\nII                 Liquids having flash points at or above 100°F and below 140°F\r\nIIIA              Liquids having flash points at or above 140°F and below 200°F\r\nIIIB              Liquids having flash points at or above 200°F', NULL, 1, '2024-08-18 15:42:45', '2024-08-18 15:42:45'),
(6, 1, 1, 'a. A sampling pump with an MCE filter is used to collect ____.\r\nb. A sampling pump with a cyclone is used to collect ___.\r\nc. A sampling pump with an impactor is also used to collect ___.\r\nd. A sampling pump with a charcoal tube is used to collect ___ that will adsorb to the charcoal.', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'a. A sampling pump with an MCE filter is used to collect airborne particulate matter.\r\nb. A sampling pump with a cyclone is used to collect respirable airborne particulate matter.\r\nc. A sampling pump with an impactor is also used to collect airborne particulate matter.\r\nd. A sampling pump with a charcoal tube is used to collect gases and vapors that will adsorb to the charcoal.', NULL, 1, '2024-08-18 15:45:34', '2024-08-18 15:45:34'),
(7, 1, 1, 'All safety training programs should include the following. \r\nWhat are they?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Needs assessment – determine what training is needed at your facility\r\nTraining – delivered by a competent person\r\nLesson plans – training should be designed to meet the training needs,\r\nthese should include learning objectives and ways to evaluate training\r\neffectiveness\r\nRecord Keeping – training needs to be documented\r\nProgram evaluation – ensure training efforts are meeting the needs', NULL, 1, '2024-08-18 15:46:24', '2024-08-18 15:46:24'),
(8, 1, 1, 'System Safety Analysis Techniques\r\n\r\na. ___looks at all events that might happen in a process and uses management processes to minimize risk.\r\nb. ___ evaluates a process by looking at all the events happening simultaneously.\r\nc. ___looks at what will happen in a process when components fail in the process. It starts with a failure and moves forward in time to the consequence.\r\nd. ___starts with the catastrophic event and moves backward in the process to look at all event sequences that may lead to the catastrophic events.', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'a. Management oversight and risk tree (MORT) looks at all events that might happen in a process and uses management processes to minimize risk.\r\nb. Simultaneous time events analysis evaluates a process by looking at all the events happening simultaneously.\r\nc. Failure modes and effect analysis (FMEA) looks at what will happen in a process when components fail in the process. It starts with a failure and moves forward in time to the consequence.\r\nd. Fault tree analysis starts with the catastrophic event and moves backward in the process to look at all event sequences that may lead to the catastrophic events. A fault tree is created with the roots of the tree leading to the catastrophic event at the top.', NULL, 1, '2024-08-18 15:48:51', '2024-08-23 13:25:22'),
(9, 1, 1, 'LFL (lower flammable limit)\r\n\r\nThe atmosphere in a confined space must be ___ of the LFL prior to entry.', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'The atmosphere in a confined space must be below 10% of the LFL prior to entry.', NULL, 1, '2024-08-18 15:49:48', '2024-08-23 13:23:28'),
(10, 1, 1, 'Increasing the angle of a portable extension against a wall will..', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Increasing the angle of a portable extension against a wall will increase the frictional forces at the foot of the ladder. The weight of the ladder is being supported at both ends. Some of the weight is supported at the foot and the rest of the weight is supported on the wall. As the angle of the ladder increases, more of the weight is transferred to the foot of the ladder. This increases the normal forces of the foot. \r\n\r\nFrictional forces (Ff = μN) are calculated by the product of the friction coefficient between the surface and the foot of the ladder and the normal force of the ladder. \r\n\r\nSince the normal forces are increasing, the frictional forces also increase. Of course, this means there is less weight (and less friction) on the wall. The ladder is more likely to move sideways.', NULL, 1, '2024-08-18 15:50:51', '2024-08-18 15:50:51'),
(11, 1, 1, 'Heat Stress\r\n\r\nThe WB is ___ which the temperature of a thermometer with its bulb kept wet with a wick. It is a measure of the heat loss through evaporation.\r\n\r\nThe DB is the ___ . It measures the dry air temperature.\r\n\r\nThe GT is the ___ which the temperature measured by a thermometer with its bulb kept in a globe painted flat black. It is a measure of the radiant energy.', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'The WB is Wet Bulb which the temperature of a thermometer with its bulb kept wet with a wick. It is a measure of the heat loss through evaporation.\r\n\r\nThe DB is the Dry Bulb . It measures the dry air temperature.\r\n\r\nThe GT is the Globe Temperature which the temperature measured by a thermometer with its bulb kept in a globe painted flat black. It is a measure of the radiant energy.', NULL, 1, '2024-08-18 15:53:00', '2024-08-18 15:53:00'),
(12, 1, 1, 'Product Liability\r\n\r\nPlaintiffs in a product liability lawsuit must show that the product was defective, the defect existed when it left the defendant’s hands, and the defect caused the injury or harm.\r\n\r\nDefine\r\na. Warranty liability\r\n\r\nb. Negligence\r\n\r\nc. Strict liability', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'a. Warranty liability includes merchantability and fitness for a particular purpose. Implied warranty is a branch of contract law. Merchantability applies to companies that normally offer a product. There is an implied warranty that the product meets some level of quality and is safe to use.\r\n\r\nb. Negligence lawsuits must show the defendant had a duty to provide a product free of the claimed defect and was negligent in performing that duty. Negligence is a behavior and can be difficult to prove.\r\n\r\nc. Strict liability - A manufacturer is strictly liable in tort when the company sold a product with a defect and the defect caused an injury. It does not deal with the behavior of the company.', NULL, 1, '2024-08-18 15:55:18', '2024-08-18 15:55:18'),
(13, 1, 1, 'Abraham Maslow developed a motivational theory of “The Hierarchy of Needs”. ___ is the highest priority of persons who have already satisfied needs lower down on the hierarchy.', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Abraham Maslow developed a motivational theory of “The Hierarchy of Needs”. Self actualization is the highest priority of persons who have already satisfied needs lower down on the hierarchy.', NULL, 1, '2024-08-18 15:56:33', '2024-08-18 15:56:33'),
(14, 1, 1, 'Personal Protective Equipment\r\n\r\nWhat is the appropriate clearance between the headband suspension and the top of a hardhat?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'The clearance (1.25 inches) is necessary to protect the head in the event a heavy object is dropped on the head.', NULL, 1, '2024-08-18 15:57:07', '2024-08-18 15:57:07'),
(15, 1, 1, 'What is \'Time value of money\'?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'The time value of money is the time it will take to recover an investment based on future savings.', NULL, 1, '2024-08-18 15:57:54', '2024-08-18 15:57:54'),
(16, 1, 1, 'What is \'The future value of money\'?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'The future value of money would be the value of the investment if the same amount of money were put into an interest-bearing loan account at a certain percentage. T', NULL, 1, '2024-08-18 15:58:16', '2024-08-18 15:58:16'),
(17, 1, 1, 'What is difference between Loss prevention and Loss reduction with examples?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Loss prevention focusses on reducing the likelihood that a loss will occur. Training employees on electrical safety reduces the likelihood that an employee will be injured when working with or around electricity. \r\n\r\nInstalling firewalls to reduce the spread of fire, installing automatic fire sprinklers are examples of loss reduction. Loss reduction focusses on reducing the severity of loss aften an incident has already taken place.', NULL, 1, '2024-08-18 15:59:49', '2024-08-18 15:59:49'),
(18, 1, 1, 'There are several types of cumulative trauma disorders (CTD). \r\nName some CTD.', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'a. Roofers knee (also called carpetlayer\'s knee) is a CTD known as prepatellar bursitis\r\nb. Tennis elbow or epicondylitis is a CPD\r\nc. Ganglion cyst occurs when a tendon sheath swelling is filled with synovial fluid. This is commonly found on the radial side of the wrist and is also a CTD.', NULL, 1, '2024-08-18 16:01:36', '2024-08-18 16:01:36'),
(19, 1, 1, 'In a system safety design, which design (Fail safe, Fail operational, Fail passive, Intrinsically safe) would be suitable for hazardous atmospheres?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'The design philosophy most suitable for hazardous atmospheres is \'intrinsically safe\'. Intrinsically safe design limits the possibility of sparks igniting the atmosphere, by containerizing the connection to keep sparks contained. All the others (Fail safe, Fail operational, Fail passive) allow failure, but seek to engineer out hazards that allow it. Intrinsically safe is designed to minimize any failure, though it does still occur.', NULL, 1, '2024-08-18 16:02:56', '2024-08-18 16:02:56'),
(20, 1, 1, 'How often must employees retrained in respiratory safety', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Annually', NULL, 1, '2024-08-18 16:03:19', '2024-08-18 16:03:19'),
(21, 1, 1, 'According to the department of transportation (dot), hazardous waste must be shipped using what type of shipping document?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Uniform hazardous waste manifest.', NULL, 1, '2024-08-18 16:03:43', '2024-08-18 16:03:43'),
(22, 1, 1, 'A danger point or a line is a point where dangerous actions occurs on a machine or a pinch point that narrows to what size or less?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, '3/8\" this is the approximate thickness of a finger.', NULL, 1, '2024-08-18 16:04:19', '2024-08-18 16:04:19'),
(23, 1, 1, 'Which type of study is used to determine the degree of associations between various risk factors and outcomes?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Case Control Study', NULL, 1, '2024-08-18 16:05:04', '2024-08-18 16:05:04'),
(24, 1, 1, 'One standard deviation is equal to ___ % of data set.', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, '68', NULL, 1, '2024-08-18 16:05:19', '2024-08-18 16:05:19'),
(25, 1, 1, 'Event tree and fault tree analysis were developed for ___  in the 1950\'s and 1960\'s.', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Weapons systems', NULL, 1, '2024-08-18 16:05:55', '2024-08-18 16:05:55'),
(26, 1, 1, 'What is Risk-based inspection (RBI)?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Risk-based inspection (RBI) is a strategy gaining ground that considers the holistic effect of pressure vessel service against prescriptive requirements for pressure vessel safety. Sometimes the results of an RBI program recommend more frequent inspection intervals than are required by ASME, and sometimes the results of the RBI program recommend less frequent intervals. In many cases, an RBI program recommends tests in addition to those required by codes and regulations.', NULL, 1, '2024-08-18 16:06:41', '2024-08-18 16:06:41'),
(27, 1, 1, 'What is Reliability-centered maintenance (RCM)?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Reliability-centered maintenance (RCM) is a method to define an appropriate maintenance strategy based on the criticality of the equipment and the effectiveness of maintenance tasks to produce acceptable reliability performance. A task selection guide is developed to define the actual maintenance tasks and their intervals based on the type of service of the equipment. This information helps the maintenance and operations professionals to choose maintenance tasks at appropriate intervals.', NULL, 1, '2024-08-18 16:06:59', '2024-08-18 16:06:59'),
(28, 1, 1, 'What is a lost workday, restricted workday and a recordable injury?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'An injury that causes an employee to miss one complete day of work (or shift) is a lost workday case. An injury that causes an employee to alter their regular job assignment is a restricted workday case. An injury that requires medical attention is a recordable injury. See the regulations on what is considered medical attention.', NULL, 1, '2024-08-18 16:07:46', '2024-08-18 16:07:46'),
(29, 1, 1, 'What is an electrical ground and an electrical bond?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'An electrical ground is an electrical connection between an object and ground. An electrical bond is an electrical connection between two objects. It is important to electrically bond containers when transferring flammable fluids.', NULL, 1, '2024-08-18 16:08:53', '2024-08-18 16:08:53'),
(30, 1, 1, 'Who is a mentor?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'A mentor is a person outside the employee’s line of supervision that provides guidance in career development and problem resolution.', NULL, 1, '2024-08-18 16:09:21', '2024-08-18 16:09:21'),
(31, 1, 1, 'The maximum length of a dead-end corridor using sprinkler protection is ___ ft. in a mercantile occupancy.', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'The maximum length of a dead-end corridor using sprinkler protection is 50 ft. in a mercantile occupancy.', NULL, 1, '2024-08-18 16:10:09', '2024-08-18 16:10:09'),
(32, 1, 1, 'What is a Firestop?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'A firestop or fire-stopping is a form of passive fire protection that is used to seal around openings and between joints in a fire-resistance-rated wall or floor assembly. Firestops are designed to maintain the fireproofing of a wall or floor assembly allowing it to impede the spread of fire and smoke. Fire stops are used to prevent the hot gases in a fire from spreading through the structures. Fire stops may be fire walls, and they may be caulks or insulation placed in gaps between floors and rooms.', NULL, 1, '2024-08-18 16:10:44', '2024-08-18 16:10:44'),
(33, 1, 1, 'What is Behavior-based safety?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Behavior-based safety is based on the measurement of safe behaviors in the workplace. It is an employee-driven process that will only succeed with the active participation of employees.', NULL, 1, '2024-08-18 16:11:30', '2024-08-18 16:11:30'),
(34, 1, 1, 'Horizontal and Vertical Standards', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Standards are referred to as either horizontal or vertical. Horizontal standards are those standards that apply to all industries and employers. For example, fire prevention and protection standards are horizontal standards. Vertical standards are those standards that apply only to particular industries and employers. Standards that apply only to the construction industry are an example of vertical standards.', NULL, 1, '2024-08-18 16:13:14', '2024-08-18 16:13:14'),
(35, 1, 1, 'What is a General Duty Clause?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Each standard promulgated by OSHA cannot cover every specific detail. Therefore, OSHA has implemented a “general duty clause” into the regula-tions. The General Duty Clause states that an employer shall furnish “a place of employment which is free from recognized hazards that are causing or are likely to cause death or serious physical harm to its employees.” Where there is no specific standard, OSHA will use the general duty clause for the issuance of citations and fines.', NULL, 1, '2024-08-18 16:13:51', '2024-08-18 16:13:51'),
(36, 1, 1, 'What is \'PEMDAS\'?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'PEMDAS identifies the order of operations listed as follows:\r\n1. Parentheses,\r\n2. Exponents,\r\n3. Multiplication,\r\n4. Division,\r\n5. Addition,\r\n6. Subtraction.', NULL, 1, '2024-08-18 16:14:33', '2024-08-18 16:14:33'),
(37, 1, 1, 'Boyle’s Law', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Boyle’s law states that at a constant temperature, a fixed mass of gas occu-pies a volume that is inversely proportional to the pressure exerted upon it. Boyle’s law is written mathematically as\r\nP1V1 = P2V2\r\nwhere P = pressure exerted and V = volume of gas.', NULL, 1, '2024-08-18 16:15:33', '2024-08-18 16:15:33'),
(38, 1, 1, 'Charles’ Law', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Charles’ law states that at constant pressure, the volume occupied by a fixed mass of gas is directly proportional to the absolute temperature. Charles’ law is written mathematically as:\r\nV1/T1=V2/T2\r\nwhere V = volume of gas and T = temperature of gas (kelvin temperature scale).', NULL, 1, '2024-08-18 16:16:28', '2024-08-18 16:16:28'),
(39, 1, 1, 'Ideal Gas Law', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'An ideal gas can be defined as a gas where all internal energy is in kinetic energy form and any change causes a change in temperature. The ideal gas law is written as follows:\r\n\r\nPV=nRT\r\n\r\nwhere\r\nP = absolute pressure (total pressure exerted on a system [also written as psia]). Absolute pressure is equal to the gauge pressure plus the atmospheric pressure (unit of atmosphere or atm)\r\nV = volume (L)\r\nT = temperature (K)', NULL, 1, '2024-08-18 16:17:10', '2024-08-18 16:17:10'),
(40, 1, 1, 'Conversion Factors for Converting Pressure Units to Atmospheric Pressure Units.', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'To convert pressures to atmosphere pressures, use the following conversion factors:\r\n1 atm = 14.6959488 pounds per square inch (psi),\r\n1 atm = 29.9246899 inches of mercury (in. Hg),\r\n1 atm = 760 mm mercury (mm Hg),\r\n1 atm = 760 torr (torr),\r\n1 atm = 101,325 pascals (Pa),\r\n1 atm = 101.325 kilopascals (kPa),\r\n1 atm = 1.01325 bar (bar).', NULL, 1, '2024-08-18 16:18:13', '2024-08-18 16:18:13'),
(41, 1, 1, 'Conversion Factors for Converting Units of Volume to Liters.', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, '1 L = 1,000 milliliters (mL)\r\n1 L = 1,000 cubic centimeters (cm3)\r\n1 L = 1 cubic decimeter (dm3)\r\n1 L = 0.001 cubic meters (m3)\r\n1 L = 0.264172051 U.S. gallons (gal)\r\n1 L = 1.0566882 U.S. quarts (qts)', NULL, 1, '2024-08-18 16:18:29', '2024-08-18 16:18:29'),
(42, 1, 1, 'Above what height must a registered professional engineer design scaffolding?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Anything over 125 feet high\r\n\r\nAny competent person may construct scaffolds up to 125 feet (38 meters) high. Anything higher than that must be designed by a registered professional engineer; see 1926.452(b)(10)', NULL, 1, '2024-08-25 08:56:43', '2024-08-25 08:56:43'),
(43, 1, 1, 'A suspension scaffold held by rope or wire must be capable of supporting what weight?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, '6 times the load\r\n\r\nSuspension scaffolds contain one or more working platforms suspended by ropes or wires. Each suspension rope or wire must be capable of supporting six times the load and must be secured in order to prevent swaying.', NULL, 1, '2024-08-25 08:57:11', '2024-08-25 08:57:11'),
(44, 1, 1, 'Approximately how many gallons of distilled water need to be added to 1 gallon of a pH 3 liquid to adjust the pH to 5?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'The pH of a solution indicates its hydrogen ion concentration. \r\nThe formula for pH is pH = -log[H+], where [H+] represents the hydrogen ion molarity. The pH scale is logarithmic, meaning each whole number change on the pH scale represents a tenfold change in hydrogen ion concentration.\r\n\r\nFor instance, the hydrogen ion molarity of a pH 3 solution is 10^-3 M. If you dilute this solution by a factor of 10 (adding 10 gallons of distilled water), the new pH becomes 4 (10^-4 M). To achieve a pH of 5 (10^-5 M), you would need to dilute the original solution by a factor of 100, which requires adding 100 gallons of distilled water to the original 1 gallon of pH 3 liquid.\r\n\r\nDistilled water has a neutral pH of 7. No matter how much distilled water is added, the pH of an acidic solution cannot be raised above 7. Similarly, the pH of a basic solution cannot be lowered below 7 by adding distilled water.', NULL, 1, '2024-08-25 09:12:54', '2024-08-25 09:12:54'),
(45, 1, 1, 'What does the blue section of the NFPA diamond represent?', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, 'Health hazards.\r\n\r\nThe NFPA diamond is a labeling system used to identify the hazards of a material. It is divided into four colored sections:\r\n•	Red for flammability hazards\r\n•	Blue for health hazards\r\n•	Yellow for instability/reactivity hazards\r\n•	White for special hazards\r\n\r\nEach colored section, except for white, contains a number (0-4) indicating the hazard level, with 4 being the highest hazard and 0 indicating no hazard. The blue section specifically represents health hazards, indicating the potential harm a material can cause to human health.', NULL, 1, '2024-08-25 09:13:30', '2024-08-25 09:13:30'),
(46, 1, 1, '<p><strong>For a substance to be classified as \"radioactive,\" it must have what specific&nbsp;activity?</strong></p>', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, '<p>&gt;70 Bq/g (Becquerels per gram)</p><p>&nbsp;</p><p>The United States Department of Transportation separates hazardous materials, specifically for transportation purposes, into nine different classifications. Class 7 is radioactive materials, which have a specific activity above 70 Bq/g (Becquerels per gram).</p><p>&nbsp;</p><p>One becquerel is the activity of a quantity of radioactive material in which one nucleus decays per second. Thus, a becquerel is equivalent to an inverse second, s−1. In more simple terms, becquerel is the SI unit of radioactivity, corresponding to one disintegration per second.</p>', NULL, 1, '2024-08-26 10:32:55', '2024-08-26 10:32:55'),
(47, 1, 1, '<p><strong>What is the reference value (reference level) used for sound power calculations?</strong></p>', NULL, 0, 0, 0, NULL, NULL, NULL, NULL, '<p>10-12&nbsp;W</p><p>&nbsp;</p><p>The sound power of a source is expressed in terms of its sound power level and is written as (Lw&nbsp;or PWL). Sound power must be compared against a reference level, and it is helpful to memorize the sound power reference level, which is&nbsp;10-12&nbsp;W.</p>', NULL, 1, '2024-08-26 10:33:53', '2024-08-26 10:33:53');
