(100, 1, 13, 'Briefly discuss the significance of industrial safety acts and laws such as the Factories Act, 1948 and the Workmen\'s Compensation Act', NULL, 1, 1, 109, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 07:21:00', '2024-08-05 07:21:00'),
(101, 1, 13, 'Describe the role of communication in promoting safety within an organization.What are some common barriers to effective communication in safety management?', NULL, 2, 2, 107, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 07:22:14', '2024-08-05 07:22:14'),
(102, 1, 13, 'Briefly discuss the purpose and scope of safety education and training programs in the workplace.', NULL, 2, 2, 106, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 07:23:00', '2024-08-05 07:23:00'),
(103, 1, 13, 'What is the importance of employee participation in safety initiatives? Provide examples of methods for encouraging employee involvement.', NULL, 2, 2, 108, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 07:24:02', '2024-08-05 07:24:02'),
(104, 1, 13, 'Outline the steps involved in organizing for safety within an organization. Include a discussion on the structure and functions of safety committees.', NULL, 2, 2, 106, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 07:25:06', '2024-08-05 07:25:06'),
(105, 1, 14, 'Explain the concept of the fire triangle and its relevance to fire prevention.', NULL, 1, 1, 110, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 07:26:46', '2024-08-05 07:26:46'),
(106, 1, 14, 'What are the main types of fire protection systems?', NULL, 1, 1, 112, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 07:27:14', '2024-08-05 07:27:14'),
(107, 1, 14, 'Describe the role of fire alarms in fire safety', NULL, 1, 1, 113, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 07:27:39', '2024-08-05 07:27:39'),
(108, 1, 14, 'Briefly discuss the importance of fire drills in maintaining safety awareness.', NULL, 1, 1, 111, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 07:28:17', '2024-08-05 07:28:17'),
(109, 1, 14, 'Explain the significance of industrial fire protection systems such as sprinklers, hydrants and standpipes. How do these systems contribute to workplace safety?', NULL, 2, 2, 112, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 07:31:03', '2024-08-05 07:31:03'),
(110, 1, 14, 'Describe the objectives and components of fire-safe building design. How do fire-resistant materials and structural integrity play a role in building fire safety?', NULL, 2, 2, 113, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 08:40:51', '2024-08-05 08:40:51'),
(111, 1, 14, 'Discuss the principles of explosion protection systems. How do rupture discs and suppression systems mitigate explosion hazards in industrial settings?', NULL, 2, 2, 114, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 08:41:26', '2024-08-05 08:41:26'),
(112, 1, 14, 'Evaluate the hazards associated with various substances such as LPG, ammonia, sulfur dioxide, and chlorine in the context of explosion protection. What measures can be taken to mitigate these hazards effectively?', NULL, 2, 2, 114, NULL, NULL, NULL, NULL, NULL, NULL, 1, '2024-08-05 08:41:56', '2024-08-05 08:41:56'),
