INSERT INTO `course_basic_infos` (`id`, `created_by`, `course_category_id`, `course_id`, `course_name`, `duration_type`, `duration`, `credits`, `course_price`, `course_size`, `course_description`, `course_image`, `status`, `created_at`, `updated_at`) VALUES
(1, 1, 1, 'B-01', 'Certified Safety Professional', '2', 160, NULL, 30000, 0, 'A CSP candidate’s professional practice is typically spent implementing safety management systems, making worksite assessments to determine risks, assessing potential hazards and controls, evaluating risks and hazard control measures, investigating incidents, maintaining and evaluating incident and loss records, and preparing emergency response plans, among other possible duties. A CSP may also have environmental management system responsibilities, including managing SH&E programs that can cover up to 1,000 or more employees.\r\n\r\nSafety responsibilities of this level are found in virtually every industry including petroleum exploration, production and refining, manufacturing, construction, healthcare, and insurance.', '1722175970.jpg', 1, '2024-07-28 14:12:50', '2024-11-27 10:13:42'),
(2, 1, 2, 'D-03', 'Advanced Diploma in Offshore Rig, Oil and Gas Safety', '2', 80, NULL, 11999, 0, 'This comprehensive program is designed to equip professionals with in-depth knowledge and skills necessary to manage and mitigate risks in the offshore, rig, oil, and gas sectors. This course offers a blend of theoretical knowledge and practical insights, ensuring that participants are well-versed in the latest safety protocols and industry standards. It is tailored to address the unique challenges faced in these high-risk environments, focusing on creating a culture of safety that protects both personnel and the environment.', '1722229397.jpg', 1, '2024-07-29 05:03:17', '2024-08-21 09:07:53'),
(3, 1, 2, 'D-02', 'Advanced Diploma in Fire and Industrial Safety Management', '2', 80, NULL, 11999, 0, 'This comprehensive program is designed to equip professionals with the latest knowledge and skills required to excel in the field of fire and industrial safety. Our course integrates practical insights and theoretical foundations to ensure a robust understanding of safety management, risk assessment, and emergency response strategies.', '1722661427.jpg', 1, '2024-08-03 05:03:47', '2024-08-21 09:08:04'),
(4, 1, 2, 'D-01', 'Advanced Diploma in Occupational Health Safety and Environmental Management', '2', 80, NULL, 11999, 0, 'This comprehensive program is designed to equip professionals with in-depth knowledge and practical skills necessary to excel in the fields of occupational safety, health, and environmental management. Our course integrates the latest industry standards and best practices, ensuring that you are well-prepared to handle the dynamic challenges in today\'s workplaces.', '1722667668.jpg', 1, '2024-08-03 06:47:48', '2024-08-21 09:08:23'),
(5, 1, 2, 'D-05', 'Diploma in Environmental Safety', '2', 80, NULL, 11999, 0, 'This comprehensive program designed to equip professionals with in-depth knowledge and practical skills in environmental safety management. This course bridges the gap between theoretical concepts and real-world applications, ensuring that graduates are well-prepared to address environmental challenges in various industrial and corporate settings. Our curriculum is tailored to meet the evolving needs of the environmental safety sector, emphasizing sustainable practices and compliance with global safety standards.', '1722681810.jpg', 1, '2024-08-03 10:43:30', '2024-08-21 09:08:35'),
(6, 1, 2, 'D-04', 'Diploma in Construction Safety', '2', 80, NULL, 11999, 0, 'This comprehensive program is designed to equip professionals with in-depth knowledge and skills in managing safety and health in the construction industry. This course is tailored to meet the needs of the modern construction environment, focusing on risk management, legal compliance, and the development of a safety-conscious culture.', '1722834377.jpg', 1, '2024-08-05 05:06:17', '2024-08-21 09:08:46'),
(7, 1, 2, 'D-06', 'Diploma in Industrial Safety', '2', 80, NULL, 11999, 0, 'This course is designed to equip professionals with comprehensive knowledge and skills in industrial safety, emphasizing practical applications and theoretical understanding. Our course is ideal for those looking to excel in the field of industrial safety and health management.', '1722839597.jpg', 1, '2024-08-05 06:33:17', '2024-08-21 09:09:09'),
(8, 1, 2, 'D-07', 'Advanced Diploma in Chemical Plant Processing Safety and Management', '2', 80, NULL, 11999, 0, 'This comprehensive program is designed to equip professionals with cutting-edge skills and knowledge essential for managing safety and operational aspects in chemical processing environments. Through a blend of theoretical knowledge and practical applications, this program aims to enhance the safety standards and efficiency of chemical plants.', '1724227300.jpg', 1, '2024-08-21 08:01:40', '2024-08-21 09:09:29'),
(9, 1, 2, 'D-08', 'Diploma in Fire and Safety Engineering Techniques', '2', 120, NULL, 15999, 0, 'This comprehensive program is designed to equip professionals with advanced knowledge and skills in the field of fire and safety engineering. Our course is tailored to meet the evolving demands of the industry, ensuring that our graduates are well-prepared to handle complex safety challenges in various environments. Through a blend of theoretical knowledge and practical application, this course offers an in-depth understanding of fire safety principles, risk management, and the latest safety technologies.', '1724227394.jpg', 1, '2024-08-21 08:03:14', '2024-08-21 09:07:03'),
(10, 1, 2, 'D-13', 'Post Diploma in Fire and Safety Engineering Techniques', '2', 80, NULL, 11999, 0, 'The Post Diploma in Fire and Safety Engineering Techniques is an advanced program designed to equip professionals with in-depth knowledge and practical skills in fire and safety engineering. This course builds upon foundational knowledge and focuses on the latest techniques, technologies, and regulations in fire safety. It aims to prepare candidates for leadership roles in safety management and engineering, enhancing their ability to protect lives and property from fire hazards.', '1724228053.jpg', 1, '2024-08-21 08:14:13', '2024-08-21 09:09:54'),
(11, 1, 2, 'D-14', 'Post Diploma in Health Safety Environment and Management', '2', 80, NULL, 11999, 0, 'The Post Diploma in Health Safety Environment & Management program is a comprehensive advanced course designed to equip professionals with the knowledge and skills necessary to excel in the field of health, safety, and environmental management. This program covers critical aspects of risk management, safety protocols, and environmental regulations, combining theoretical knowledge with practical application to ensure effective implementation in various organizational settings.', '1724228162.jpg', 1, '2024-08-21 08:16:02', '2024-08-21 09:10:12'),
(12, 1, 2, 'D-12', 'Post Diploma in Fire and Industrial Management', '2', 80, NULL, 11999, 0, 'The Post Diploma in Fire and Industrial Management program is designed to provide advanced knowledge and practical skills in fire safety and industrial management. This program focuses on the principles of fire prevention, risk assessment, and emergency response within industrial settings. It is tailored for professionals seeking to enhance their expertise in managing fire safety and industrial hazards to ensure a safe working environment.', '1724228255.jpg', 1, '2024-08-21 08:17:35', '2024-08-21 09:10:28'),
(13, 1, 2, 'D-15', 'Post Diploma in Petrochemical Process Safety and Engineering', '2', 80, NULL, 11999, 0, 'The Post Diploma in Petro Chemical Process Safety & Engineering provides an in-depth understanding of safety principles and engineering practices essential for the petrochemical industry. This comprehensive program covers the latest standards and techniques in process safety, hazard management, and engineering solutions, equipping professionals with the skills needed to ensure the safe and efficient operation of petrochemical facilities.', '1724228353.jpg', 1, '2024-08-21 08:19:13', '2024-08-21 09:10:39'),
(14, 1, 2, 'D-16', 'Post Diploma in Environment Safety Engineering', '2', 80, NULL, 11999, 0, 'The Post Diploma in Environmental Safety Engineering is designed for individuals who want to advance their knowledge and skills in managing environmental safety. This course focuses on understanding environmental hazards, risk assessment, and the implementation of effective safety management practices in various industries. Participants will gain a comprehensive understanding of environmental laws, safety regulations, and engineering techniques to minimize environmental risks and ensure a sustainable and safe working environment.', '1737469304.jpg', 1, '2025-01-21 14:21:44', '2025-01-23 07:24:12');
